					$filtered_qty = apply_filters( 'wc_mnm_child_item_quantity_input_default_value', $qty, $this, $this->get_container() );
					if ( 0 === $filtered_qty ) {
						$qty = 0;
					}
				}
			} else {
				$qty = $this->get_quantity( 'min' ) ? $this->get_quantity( 'min' ) : '';

